/**
 * Luma Compliant Socket.IO v4.x Native Protocol Engine
 * Релизный автономный модуль v0.99.1.22 (Финальная сборка)
 */
(function(global) {
    'use strict';

    var LumaSocket = function() {
        this.connected = false;
        this._callbacks = {};
        this._sendBuffer = [];
        this.ws = null;
    };

    LumaSocket.prototype.on = function(event, callback) {
        this._callbacks[event] = this._callbacks[event] || [];
        this._callbacks[event].push(callback);
    };

    LumaSocket.prototype.emit = function(event, data) {
        // СТРОГИЙ СИНТАКСИС v0.99.1.22: Чистый Socket.IO v4 формат текстового фрейма
        var payload = "42" + JSON.stringify([event, data]);

        if (this.ws && this.ws.readyState === WebSocket.OPEN && this.connected) {
            this.ws.send(payload);
        } else {
            console.warn("[LUMA WS] Сокет еще не согласован. Пакет помещен в буфер:", event);
            this._sendBuffer.push(payload);
        }
    };

    LumaSocket.prototype.connect = function() {
        var self = this;
        var wsUrl = window.location.origin.replace(/^http/, 'ws') + "/socket.io/?EIO=4&transport=websocket";

        console.log("[LUMA WS] Открытие WebSocket канала:", wsUrl);
        this.ws = new WebSocket(wsUrl);

        this.ws.onopen = function() {
            // Отправляем обязательный стартовый пакет инициализации сессии Engine.IO
            self.ws.send("40");
        };

        this.ws.onmessage = function(e) {
            var raw = e.data;

            // Обработка системного пинга сервера Flask (Формат "2")
            if (raw === "2") {
                self.ws.send("3"); // Отвечаем понгом "3", удерживая соединение от таймаута
                return;
            }

            // Обработка успешного handshake от пространства имен (Формат "40")
            if (raw.startsWith("40")) {
                self.connected = true;
                console.log("[LUMA SOCKET] Протокол полностью согласован. Активация передачи данных.");

                // Моментально выстреливаем накопленный буфер пакетов
                while (self._sendBuffer.length > 0) {
                    self.ws.send(self._sendBuffer.shift());
                    console.log("[LUMA WS] Пакет из буфера успешно передан на бэкенд Luma.");
                }

                if (self._callbacks['connect']) {
                    self._callbacks['connect'].forEach(function(f) { f(); });
                }
                return;
            }

            // Обработка входящих событий (Формат "42...")
            if (typeof raw === 'string' && raw.startsWith('42')) {
                try {
                    var cleanJson = raw.substring(2); // Аккуратно отрезаем маркер "42", оставляя чистый JSON
                    var parsed = JSON.parse(cleanJson);
                    var eventName = parsed[0];
                    var eventData = parsed[1];

                    if (self._callbacks[eventName]) {
                        self._callbacks[eventName].forEach(function(callbackFunction) {
                            callbackFunction(eventData);
                        });
                    }
                } catch(err) {
                    console.error("[LUMA WS ERROR] Ошибка парсинга входящего фрейма:", err, raw);
                }
            }
        };

        this.ws.onclose = function() {
            self.connected = false;
            console.warn("[LUMA SOCKET] Канал связи закрыт. Реконнект через 2 секунды...");
            setTimeout(function() { self.connect(); }, 2000);
        };
    };

    global.io = function() {
        var client = new LumaSocket();
        client.connect();
        return client;
    };
})(this);
